import React, { useState } from "react";
import { motion } from "framer-motion";

export default function Portfolio() {
  const [darkMode, setDarkMode] = useState(true);
  const [expandedWork, setExpandedWork] = useState(null);

  const workExperience = [
    {
      id: 1,
      company: "HeadStarter AI",
      role: "Software Engineering Fellow",
      period: "Jul 2024 - Aug 2024",
      description: "Accepted into the prestigious HeadStarter AI Software Engineering Fellowship. Over the course of 7 weeks, I am engaged in creating 5 innovative AI applications and participating in weekly hackathons. This fellowship provides an opportunity to expand and refine my portfolio while collaborating with engineers from top companies such as Google, Apple, Bloomberg, Citadel, Two Sigma, Meta, and other leading startups.",
      logo: "/logos/headstarter.svg",
      link: "https://headstarter.co/"
    },
    {
      id: 2,
      company: "CodePath Tech Fellowship",
      role: "Technical Interview Prep",
      period: "Sep 2024 - Nov 2024",
      description: "Participated in intensive technical interview preparation program, focusing on data structures, algorithms, and system design. Enhanced problem-solving skills and gained valuable insights into the software engineering interview process.",
      logo: "/logos/codepath.svg",
      link: "https://codepath.org/"
    },
    {
      id: 3,
      company: "Whitman Box Office",
      role: "University Ticket Software and Financial Manager",
      period: "Sep 2024 - Present",
      description: "Managing university ticket sales software and financial operations. Responsible for overseeing ticket sales, financial reporting, and ensuring smooth operations for campus events.",
      logo: "/logos/whitman.svg",
      link: "https://whitman.edu/"
    },
    {
      id: 4,
      company: "Tacah Technology",
      role: "CEO and Co-founder",
      period: "Jan 2022 - Present",
      description: "Leading technology company focused on innovative solutions. Co-founded and currently serving as CEO, driving strategic vision and overseeing company operations.",
      logo: "/logos/tacah.svg",
      link: "#"
    },
    {
      id: 5,
      company: "Whitman College",
      role: "Student Digital Lab Assistant",
      period: "Feb 2025 - Present",
      description: "Supporting digital lab operations and assisting students with technology-related projects. Providing technical support and guidance for various digital initiatives.",
      logo: "/logos/whitman.svg",
      link: "https://whitman.edu/"
    }
  ];

  const projects = [
    {
      title: "Native Plants AI Support",
      description: "Built an AI assistant using Next.js, OpenAI, Pinecone, and MUI, boosting efficiency with real-time, accurate responses.",
      tech: ["Next.js", "OpenAI", "Pinecone", "MUI"],
      link: "https://github.com/Keysej",
      period: "Jan 2024 - Present"
    },
    {
      title: "Flashcards SaaS",
      description: "Built a scalable SaaS flashcard app using Next.js, React, Firebase, and Stripe, enhancing user learning experiences.",
      tech: ["Next.js", "React", "Firebase", "Stripe"],
      link: "https://github.com/Keysej",
      period: "Mar 2024 - Present"
    }
  ];

  const skills = [
    "Python", "JavaScript", "React", "Node.js", "SQL", "AWS", "MongoDB", 
    "Next.js", "Tailwind CSS", "Firebase", "Stripe", "Pinecone"
  ];

  return (
    <main className={`${darkMode ? "bg-black text-white" : "bg-white text-black"} font-sans min-h-screen transition-colors duration-500`}>
      <div className="max-w-2xl mx-auto py-12 sm:py-24 px-6">
        {/* Theme Toggle */}
        <div className="flex justify-end mb-8">
          <button 
            onClick={() => setDarkMode(!darkMode)} 
            className="inline-flex items-center justify-center whitespace-nowrap text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 hover:bg-accent hover:text-accent-foreground h-9 w-9 rounded-full px-2"
          >
            {darkMode ? "☀️" : "🌙"}
          </button>
        </div>

        {/* Hero Section */}
        <section id="hero" className="mb-16">
          <div className="mx-auto w-full max-w-2xl space-y-8">
            <div className="gap-2 flex justify-between">
              <div className="flex-col flex flex-1 space-y-1.5">
                <div className="flex">
                  <motion.span 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="inline-block text-3xl font-bold tracking-tighter sm:text-5xl xl:text-6xl/none"
                  >
                    Hi, I'm Jimale 👋
                  </motion.span>
                </div>
                <div className="flex">
                  <motion.span 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="inline-block max-w-[600px] md:text-xl"
                  >
                    CS major with minors in Data Science at Whitman College. Aspiring Data Scientist with a strong interest in Cloud Computing and practical experience in Data Engineering. Passionate about creating impactful solutions.
                  </motion.span>
                </div>
              </div>
              <div>
                <motion.span 
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.4 }}
                  className="relative flex shrink-0 overflow-hidden rounded-full size-28 border"
                >
                  <span className="flex h-full w-full items-center justify-center rounded-full bg-muted">JK</span>
                </motion.span>
              </div>
            </div>
          </div>
        </section>

        {/* About Section */}
        <section id="about" className="mb-16">
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.6 }}
          >
            <h2 className="text-xl font-bold mb-4">About</h2>
          </motion.div>
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.8 }}
          >
            <div className="prose max-w-full text-pretty font-sans text-sm text-muted-foreground dark:prose-invert">
              <p>
                CS major with minors in Data Science at Whitman College. Passionate about impactful solutions, cloud computing, and data engineering. Always learning and eager to leverage new technologies for innovation. I'm committed to continuing learning and excited to leverage emerging technologies to drive innovation.
              </p>
            </div>
          </motion.div>
        </section>

        {/* Work Experience Section */}
        <section id="work" className="mb-16">
          <div className="flex min-h-0 flex-col gap-y-3">
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 1.0 }}
            >
              <h2 className="text-xl font-bold">Work Experience</h2>
            </motion.div>

            {workExperience.map((work, index) => (
              <motion.div 
                key={work.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 1.2 + index * 0.1 }}
              >
                <a 
                  className="block cursor-pointer" 
                  href={work.link}
                  onClick={(e) => {
                    e.preventDefault();
                    setExpandedWork(expandedWork === work.id ? null : work.id);
                  }}
                >
                  <div className="rounded-lg bg-card text-card-foreground flex hover:bg-gray-800 transition-colors">
                    <div className="flex-none">
                      <span className="relative flex shrink-0 overflow-hidden rounded-full border size-12 m-auto bg-muted-background dark:bg-foreground">
                        <img 
                          src={work.logo} 
                          alt={`${work.company} logo`}
                          className="flex h-full w-full items-center justify-center rounded-full object-cover"
                          onError={(e) => {
                            // Fallback to initial if logo fails to load
                            e.target.style.display = 'none';
                            e.target.nextSibling.style.display = 'flex';
                          }}
                        />
                        <span className="flex h-full w-full items-center justify-center rounded-full bg-muted" style={{display: 'none'}}>
                          {work.company.charAt(0)}
                        </span>
                      </span>
                    </div>
                    <div className="flex-grow ml-4 items-center flex-col group">
                      <div className="flex flex-col">
                        <div className="flex items-center justify-between gap-x-2 text-base">
                          <h3 className="inline-flex items-center justify-center font-semibold leading-none text-xs sm:text-sm">
                            {work.company}
                            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="lucide lucide-chevron-right size-4 translate-x-0 transform opacity-0 transition-all duration-300 ease-out group-hover:translate-x-1 group-hover:opacity-100 rotate-0">
                              <path d="m9 18 6-6-6-6"></path>
                            </svg>
                          </h3>
                          <div className="text-xs sm:text-sm tabular-nums text-muted-foreground text-right">{work.period}</div>
                        </div>
                        <div className="font-sans text-xs">{work.role}</div>
                      </div>
                      <div 
                        className={`mt-2 text-xs sm:text-sm transition-all duration-300 ${
                          expandedWork === work.id ? 'opacity-100 max-h-96' : 'opacity-0 max-h-0 overflow-hidden'
                        }`}
                      >
                        {work.description}
                      </div>
                    </div>
                  </div>
                </a>
              </motion.div>
            ))}
          </div>
        </section>

        {/* Education Section */}
        <section id="education" className="mb-16">
          <div className="flex min-h-0 flex-col gap-y-3">
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 1.8 }}
            >
              <h2 className="text-xl font-bold">Education</h2>
            </motion.div>
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 2.0 }}
            >
              <a className="block cursor-pointer" href="https://whitman.edu">
                <div className="rounded-lg bg-card text-card-foreground flex">
                  <div className="flex-none">
                    <span className="relative flex shrink-0 overflow-hidden rounded-full border size-12 m-auto bg-muted-background dark:bg-foreground">
                      <img 
                        src="/logos/whitman.svg" 
                        alt="Whitman College logo"
                        className="flex h-full w-full items-center justify-center rounded-full object-cover"
                        onError={(e) => {
                          e.target.style.display = 'none';
                          e.target.nextSibling.style.display = 'flex';
                        }}
                      />
                      <span className="flex h-full w-full items-center justify-center rounded-full bg-muted" style={{display: 'none'}}>W</span>
                    </span>
                  </div>
                  <div className="flex-grow ml-4 items-center flex-col group">
                    <div className="flex flex-col">
                      <div className="flex items-center justify-between gap-x-2 text-base">
                        <h3 className="inline-flex items-center justify-center font-semibold leading-none text-xs sm:text-sm">
                          Whitman College
                          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="lucide lucide-chevron-right size-4 translate-x-0 transform opacity-0 transition-all duration-300 ease-out group-hover:translate-x-1 group-hover:opacity-100 rotate-0">
                            <path d="m9 18 6-6-6-6"></path>
                          </svg>
                        </h3>
                        <div className="text-xs sm:text-sm tabular-nums text-muted-foreground text-right">2022 - 2026</div>
                      </div>
                      <div className="font-sans text-xs">Bachelor of Arts in Computer Science</div>
                    </div>
                  </div>
                </div>
              </a>
            </motion.div>
          </div>
        </section>

        {/* Skills Section */}
        <section id="skills" className="mb-16">
          <div className="flex min-h-0 flex-col gap-y-3">
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 2.2 }}
            >
              <h2 className="text-xl font-bold">Skills</h2>
            </motion.div>
            <div className="flex flex-wrap gap-1">
              {skills.map((skill, index) => (
                <motion.div 
                  key={skill}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 2.4 + index * 0.05 }}
                >
                  <div className="inline-flex items-center rounded-md border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 border-transparent bg-primary text-primary-foreground shadow hover:bg-primary/80">
                    {skill}
                  </div>
                </motion.div>
              ))}
            </div>
          </div>
        </section>

        {/* Projects Section */}
        <section id="projects" className="mb-16">
          <div className="space-y-12 w-full py-12">
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 3.0 }}
            >
              <div className="flex flex-col items-center justify-center space-y-4 text-center">
                <div className="space-y-2">
                  <div className="inline-block rounded-lg bg-foreground text-background px-3 py-1 text-sm">My Projects</div>
                  <h2 className="text-3xl font-bold tracking-tighter sm:text-5xl">Check out my latest work</h2>
                  <p className="text-muted-foreground md:text-xl/relaxed lg:text-base/relaxed xl:text-xl/relaxed">
                    I've worked on a variety of projects, from simple websites to complex web applications. Here are a few of my favorites.
                  </p>
                </div>
              </div>
            </motion.div>

            <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 max-w-[800px] mx-auto">
              {projects.map((project, index) => (
                <motion.div 
                  key={project.title}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 3.2 + index * 0.1 }}
                >
                  <div className="rounded-lg bg-card text-card-foreground flex flex-col overflow-hidden border hover:shadow-lg transition-all duration-300 ease-out h-full">
                    <div className="flex flex-col px-2">
                      <div className="space-y-1">
                        <h3 className="font-semibold tracking-tight mt-1 text-base">{project.title}</h3>
                        <time className="font-sans text-xs">{project.period}</time>
                        <div className="prose max-w-full text-pretty font-sans text-xs text-muted-foreground dark:prose-invert">
                          <p>{project.description}</p>
                        </div>
                      </div>
                    </div>
                    <div className="text-pretty font-sans text-sm text-muted-foreground mt-auto flex flex-col px-2">
                      <div className="mt-2 flex flex-wrap gap-1">
                        {project.tech.map((tech) => (
                          <div key={tech} className="inline-flex items-center rounded-md border font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80 px-1 py-0 text-[10px]">
                            {tech}
                          </div>
                        ))}
                      </div>
                      <div className="flex items-center pt-2 px-2 pb-2">
                        <div className="flex flex-row flex-wrap items-start gap-1">
                          <a target="_blank" href={project.link} rel="noopener noreferrer">
                            <div className="items-center rounded-md border font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 border-transparent bg-primary text-primary-foreground shadow hover:bg-primary/80 flex gap-2 px-2 py-1 text-[10px]">
                              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="lucide lucide-globe size-3">
                                <circle cx="12" cy="12" r="10"></circle>
                                <path d="M12 2a14.5 14.5 0 0 0 0 20 14.5 14.5 0 0 0 0-20"></path>
                                <path d="M2 12h20"></path>
                              </svg>
                              View Project
                            </div>
                          </a>
                        </div>
                      </div>
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          </div>
        </section>

        {/* Hackathons Section */}
        <section id="hackathons" className="mb-16">
          <div className="space-y-12 w-full py-12">
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 3.6 }}
            >
              <div className="flex flex-col items-center justify-center space-y-4 text-center">
                <div className="space-y-2">
                  <div className="inline-block rounded-lg bg-foreground text-background px-3 py-1 text-sm">Hackathons</div>
                  <h2 className="text-3xl font-bold tracking-tighter sm:text-5xl">I like building things</h2>
                  <p className="text-muted-foreground md:text-xl/relaxed lg:text-base/relaxed xl:text-xl/relaxed">
                    Throughout my journey, I have actively participated in various hackathons. These dynamic events gather creative and motivated individuals from across the country to collaborate and build innovative projects within just 2-3 days.
                  </p>
                </div>
              </div>
            </motion.div>

            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 3.8 }}
            >
              <ul className="mb-4 ml-4 divide-y divide-dashed border-l">
                <li className="relative ml-10 py-4">
                  <div className="absolute -left-16 top-2 flex items-center justify-center bg-white rounded-full">
                    <span className="relative flex shrink-0 overflow-hidden rounded-full border size-12 m-auto">
                      <span className="flex h-full w-full items-center justify-center rounded-full bg-muted">C</span>
                    </span>
                  </div>
                  <div className="flex flex-1 flex-col justify-start gap-1">
                    <time className="text-xs text-muted-foreground">December 2024</time>
                    <h2 className="font-semibold leading-none">CodePath x AmazonNext Design Challenge</h2>
                    <p className="text-sm text-muted-foreground">Virtual Event</p>
                    <span className="prose dark:prose-invert text-sm text-muted-foreground">
                      Participated in the CodePath x AmazonNext Design Challenge, collaborating with a team to create innovative design solutions and present them to industry professionals.
                    </span>
                  </div>
                </li>
              </ul>
            </motion.div>
          </div>
        </section>

        {/* Contact Section */}
        <section id="contact">
          <div className="grid items-center justify-center gap-4 px-4 text-center md:px-6 w-full py-12">
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 4.0 }}
            >
              <div className="space-y-3">
                <div className="inline-block rounded-lg bg-foreground text-background px-3 py-1 text-sm">Contact</div>
                <h2 className="text-3xl font-bold tracking-tighter sm:text-5xl">Get in Touch</h2>
                <p className="mx-auto max-w-[600px] text-muted-foreground md:text-xl/relaxed lg:text-base/relaxed xl:text-xl/relaxed">
                  Want to chat? Feel free to reach out via my social links above or shoot me a message on LinkedIn.
                </p>
              </div>
            </motion.div>
          </div>
        </section>
      </div>

      {/* Bottom Navigation */}
      <div className="pointer-events-none fixed inset-x-0 bottom-0 z-30 mx-auto mb-4 flex origin-bottom h-full max-h-14">
        <div className="fixed bottom-0 inset-x-0 h-16 w-full bg-background to-transparent backdrop-blur-lg [-webkit-mask-image:linear-gradient(to_top,black,transparent)] dark:bg-background"></div>
        <div className="w-max p-2 rounded-full border z-50 pointer-events-auto relative mx-auto flex min-h-full h-full items-center px-1 bg-background [box-shadow:0_0_0_1px_rgba(0,0,0,.03),0_2px_4px_rgba(0,0,0,.05),0_12px_24px_rgba(0,0,0,.05)] transform-gpu dark:[border:1px_solid_rgba(255,255,255,.1)] dark:[box-shadow:0_-20px_80px_-20px_#ffffff1f_inset]">
          <div className="flex aspect-square cursor-pointer items-center justify-center rounded-full" style={{width: "40px"}}>
            <a className="inline-flex items-center justify-center whitespace-nowrap text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 hover:bg-accent hover:text-accent-foreground rounded-full size-12" href="/">
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="lucide lucide-home size-4">
                <path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 0 0 1-2-2z"></path>
                <polyline points="9 22 9 12 15 12 15 22"></polyline>
              </svg>
            </a>
          </div>
          <div data-orientation="vertical" role="none" className="shrink-0 bg-border w-[1px] h-full"></div>
          <div className="flex aspect-square cursor-pointer items-center justify-center rounded-full" style={{width: "40px"}}>
